var e=[{id:`L2_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NULL`,text:{KOREA:`역시 늘어나잖아! 이대로면 끝이 없단 말이야!`,JPN:`やっぱり増えたじゃない！　このままだとキリがないわ！`,ENG:`He multiplied! It's all over now!`,TWN:`果然在增加！照這樣下去會沒完沒了！`},stage:{bg:`UNDER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`곤란하게 됐구려. 허나 아무리 까다로운 적이라도 약점이 없을 순 없소.`,JPN:`困りましたね。しかし、いくら難敵でも何かの弱点があるはずです。`,ENG:`This is not good. However, no matter how formidable the foe, all are bound to have a weakness.`,TWN:`真是棘手啊。不過再難對付的敵人也不可能沒有弱點。`},stage:{bg:`UNDER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`PENCIL_MAGICIAN_NPC_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L6_1`,type:`dialog`,speaker:`PENCIL_MAGICIAN_NPC_NULL`,text:{KOREA:`잠깐, 저기 무리들 사이에 있는 기사, 유독 위화감이 느껴지지 않아?`,JPN:`待って、あの群れの中の騎士……ちょっと違和感があるんだけど。`,ENG:`Hold on. Doesn't that one knight in the crowd seem to particularly stand out?`,TWN:`等一下，那群人中的那個騎士，你不覺得他特別不協調嗎？`},stage:{bg:`UNDER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`PENCIL_MAGICIAN_NPC_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L7_1`,type:`dialog`,speaker:`PENCIL_MAGICIAN_NPC_NULL`,text:{KOREA:`게임에서 많이 해봤어. 본체를 처치하면, 부하들도 모두 소멸하는 기믹.`,JPN:`ゲームで見たことあるよ。本体を倒せば取り巻きも一瞬で消滅するギミック。`,ENG:`I've played a lot of games. This is a gimmick where if we defeat the original, the underlings will all vanish.`,TWN:`這是在遊戲中經常見到的機制。只要擊敗本體，手下們也會全部消失。`},stage:{bg:`UNDER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`PENCIL_MAGICIAN_NPC_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L9_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NULL`,text:{KOREA:`그랬군. 그럼 저기 보이는 녀석만 해치우면 되는 거지?`,JPN:`なるほど……じゃあ、あいつだけ倒せばいいのよね？`,ENG:`I see. So, all I need to do is defeat that one over there?`,TWN:`原來如此。那只要幹掉那邊那個傢伙就行了，對吧？`},stage:{bg:`UNDER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NULL`,text:{KOREA:`좋아, 그렇다면……!`,JPN:`よし、それなら……！`,ENG:`Okay, in that case...!`,TWN:`好吧，這樣的話……！`},stage:{bg:`UNDER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`미카와 스카이는 적을 교란시켜 주시오.`,JPN:`ミカとスカイは敵の撹乱を。`,ENG:`Mika, Sky–please distract the enemy.`,TWN:`米卡和絲凱擾亂敵人。`},stage:{bg:`UNDER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}},sfx:`FX_CUTSCEN_TADA2`},{id:`L13_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`나이엘과 케이시, 그리고 아르티는 화력을 퍼부어 잡졸들로부터 길을 열어주시오.`,JPN:`ナイエルとケイシーそしてアルティは火力で雑魚どもを処理し、道を開けてください。`,ENG:`Naielle, Kaci, and Arti–please open the path for me by pouring in all your firepower.`,TWN:`奈爾、卡西和阿爾蒂，集中火力清除小嘍囉，為我們開路。`},stage:{bg:`UNDER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`소인이 저 기사의 숨통을 끊겠소. 모두 부탁하오!`,JPN:`自分があの騎士の息の根を止めます。では、お願いします！`,ENG:`I will go and make that knight draw his last breath. I am counting on all of you!`,TWN:`在下這就去斷了那騎士的氣息。拜託大家了！`},stage:{bg:`UNDER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`RULER_JUNIOR_SPORTS_NULL`,text:{KOREA:`좋아요! 얘들아, 어서 움직이자!`,JPN:`わかった！　みんな、早く行こう！`,ENG:`Okay! Everyone, let's get moving!`,TWN:`好！大家快行動吧！`},stage:{bg:`UNDER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RULER_JUNIOR_SPORTS_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`SPEAKER_JUNIOR_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L18_1`,type:`dialog`,speaker:`SPEAKER_JUNIOR_NULL_NULL`,text:{KOREA:`하하, 오랜만에 내 발명품을 잔뜩 시험해 볼 수 있겠는데?`,JPN:`はは、久しぶりにぼくの発明品を試せるチャンスだね！`,ENG:`Haha, I guess it's time for me to give my inventions a test run.`,TWN:`哈哈，好久沒能好好測試我的發明了？`},stage:{bg:`UNDER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RULER_JUNIOR_SPORTS_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`SPEAKER_JUNIOR_NULL_NULL`,face:`UNIT_LAUGH`}}}},{id:`L20_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NULL`,text:{KOREA:`자, 잠깐! 브리핑은 내가 하려 했다고……!`,JPN:`ちょ、ちょっと！　作戦指示は私がやるつもりだったのに……！`,ENG:`W-wait! I was going to do the briefing...!`,TWN:`等，等等！本來是我要開作戰會議的……！`},stage:{bg:`UNDER`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};